import groovy.transform.CompileStatic

@CompileStatic
int sumOfSquares(List<Integer> nums) {
    nums.collect { it * it }.sum() as int
}

println sumOfSquares([1, 2, 3])  // 14

class Config { String name; int port }

def configure(Closure c) {
    def cfg = new Config()
    c.delegate = cfg
    c.resolveStrategy = Closure.DELEGATE_FIRST
    c()
    cfg
}

def result = configure {
    name = 'server'
    port = 8080
}
println "${result.name}:${result.port}"

def greet(String name) {
    "Hi $name"          // implicit return, no semicolon
}

println greet 'Ada'      // parentheses omitted
println greet('Ada')     // equivalent

class Address { String city }
class User { Address address }

def user = new User()
def city = user?.address?.city   // null, no NPE
println city ?: 'Unknown'        // Unknown

def greet(String name, String greeting = 'Hello') {
    "$greeting, $name"
}
println greet('Ada')            // Hello, Ada
println greet('Ada', 'Hi')      // Hi, Ada

def create(Map opts) { "${opts.name}:${opts.role}" }
println create(name: 'Sam', role: 'dev')

class Money {
    int cents
    Money plus(Money other) { new Money(cents: cents + other.cents) }
    String toString() { "\$${cents / 100}" }
}

def total = new Money(cents: 150) + new Money(cents: 250)
println total   // $4.0

String.metaClass.shout = { -> delegate.toUpperCase() + '!' }
println 'hi'.shout()          // HI!

class Dynamic {
    def methodMissing(String name, args) {
        "called $name with ${args*.toString()}"
    }
}
println new Dynamic().foo(1, 2)

trait Greeter {
    String greet() { "Hello from ${name()}" }
    abstract String name()
}

class Robot implements Greeter {
    String name() { 'R2D2' }
}

println new Robot().greet()   // Hello from R2D2

